namespace sv_27ba59ccdffa4ddc9875d1995e7a5ba5.Client.Models;

public class Shipment
{
    public required string TrackingNumber { get; set; }
    public required string Status { get; set; }
    public required string Location { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public List<StatusUpdate> StatusUpdates { get; set; } = [];
}

public class StatusUpdate
{
    public required string Description { get; set; }
    public required string Location { get; set; }
    public DateTime Timestamp { get; set; }
}

using sv_27ba59ccdffa4ddc9875d1995e7a5ba5.Client.Models;

namespace sv_27ba59ccdffa4ddc9875d1995e7a5ba5.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_27ba59ccdffa4ddc9875d1995e7a5ba5.Client.Models;
using sv_27ba59ccdffa4ddc9875d1995e7a5ba5.Client.Services;

namespace sv_27ba59ccdffa4ddc9875d1995e7a5ba5.Services;

public class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Memphis, TN",
            EstimatedDelivery = DateTime.Today.AddDays(2),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Los Angeles, CA", Timestamp = DateTime.Today.AddDays(-3) },
                new StatusUpdate { Description = "Departed facility", Location = "Los Angeles, CA", Timestamp = DateTime.Today.AddDays(-2).AddHours(6) },
                new StatusUpdate { Description = "Arrived at hub", Location = "Memphis, TN", Timestamp = DateTime.Today.AddDays(-1).AddHours(14) },
                new StatusUpdate { Description = "In transit to destination", Location = "Memphis, TN", Timestamp = DateTime.Today.AddHours(8) },
            ]
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "New York, NY",
            EstimatedDelivery = DateTime.Today.AddDays(-1),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Chicago, IL", Timestamp = DateTime.Today.AddDays(-5) },
                new StatusUpdate { Description = "In transit", Location = "Indianapolis, IN", Timestamp = DateTime.Today.AddDays(-4) },
                new StatusUpdate { Description = "Out for delivery", Location = "New York, NY", Timestamp = DateTime.Today.AddDays(-1).AddHours(7) },
                new StatusUpdate { Description = "Delivered", Location = "New York, NY", Timestamp = DateTime.Today.AddDays(-1).AddHours(14) },
            ]
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Seattle, WA",
            EstimatedDelivery = DateTime.Today.AddDays(5),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Location = "Seattle, WA", Timestamp = DateTime.Today.AddHours(-2) },
                new StatusUpdate { Description = "Awaiting pickup", Location = "Seattle, WA", Timestamp = DateTime.Today },
            ]
        },
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using System.Net;
using System.Net.Http.Json;
using sv_27ba59ccdffa4ddc9875d1995e7a5ba5.Client.Models;

namespace sv_27ba59ccdffa4ddc9875d1995e7a5ba5.Client.Services;

public class ClientShipmentService(HttpClient http) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == HttpStatusCode.NotFound)
        {
            return null;
        }

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_27ba59ccdffa4ddc9875d1995e7a5ba5.Client.Models
@using sv_27ba59ccdffa4ddc9875d1995e7a5ba5.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

<h2>Shipment Tracking</h2>

@if (_loading)
{
    <p><em>Loading shipment @TrackingNumber&hellip;</em></p>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger mt-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
}
else
{
    <dl>
        <dt>Tracking Number</dt>
        <dd>@_shipment.TrackingNumber</dd>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Current Location</dt>
        <dd>@_shipment.Location</dd>
        @if (_shipment.EstimatedDelivery.HasValue)
        {
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.Value.ToShortDateString()</dd>
        }
    </dl>

    <h4>Status Updates</h4>
    @if (_shipment.StatusUpdates.Count == 0)
    {
        <p>No status updates yet.</p>
    }
    else
    {
        <table class="table">
            <thead>
                <tr>
                    <th>Time</th>
                    <th>Location</th>
                    <th>Description</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in _shipment.StatusUpdates.OrderByDescending(u => u.Timestamp))
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Location</td>
                        <td>@update.Description</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;
    private readonly CancellationTokenSource _disposeCts = new();

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any previous in-flight request
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }

        _cts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, _cts.Token);
        }
        catch (OperationCanceledException) when (_disposeCts.IsCancellationRequested)
        {
            // Component is being disposed — don't update UI
            return;
        }
        catch (OperationCanceledException)
        {
            // Navigation changed the tracking number — superseded by a new load
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _disposeCts.Cancel();
        _disposeCts.Dispose();
        _cts?.Dispose();
    }
}

